import { trottle } from "~/utils/tools";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  watchQuery: true,
  async asyncData({ query, $get }) {
    let { data } = await $get("goods_category/lists", {
      params: { client: 2 },
    });
    return {
      categoryList: data,
    };
  },
  data() {
    return {
      count: 0,
      oneIndex: 0,
      twoIndex: "",
      threeIndex: "",
      categoryOne: [],
      categoryTwo: [],
      categoryThree: [],
      sortType: "",
      saleSort: "desc",
      priceSort: "desc",
      page: "",
      goodsList: [],
      cateId: 0,
      isHasGoods: true,
    };
  },
  created() {
    this.changeSortType = trottle(this.changeSortType, 500, this);
  },
  methods: {
    changeData(id) {
       const { categoryList } = this;
      this.setIndex(id)
      this.categoryOne = categoryList;
      this.categoryTwo = categoryList[this.oneIndex] ? categoryList[this.oneIndex].sons : [];

      this.categoryThree = this.categoryTwo[this.twoIndex] ? this.categoryTwo[this.twoIndex].sons : [];

      this.setCateId(id)
      this.getGoods();
    },
    setCateId(id) {
      if(this.twoIndex == '' && this.threeIndex == '' && this.oneIndex !== '') {
        this.cateId = this.categoryOne[this.oneIndex].id
      }
      if(this.threeIndex == '' && this.twoIndex !== '') {
        this.cateId = this.categoryTwo[this.twoIndex].id
      }
      if(id) {
        this.cateId = id;
      }
    },
    setIndex(id) {
       const { categoryList } = this;
        categoryList.some((oitem, oindex) => {
          if (oitem.id === id) {
            this.oneIndex = oindex;
            this.twoIndex = "";
            this.threeIndex = "";
            return true;
          }
          return oitem.sons && oitem.sons.some((witem, windex) => {
            if (witem.id === id) {
              this.oneIndex = oindex;
              this.twoIndex = windex;
              this.threeIndex = "";
              return true;
            }
            return witem.sons && witem.sons.some((titem, tindex) => {
              if (titem.id === id) {
                this.oneIndex = oindex;
                this.twoIndex = windex;
                this.threeIndex = tindex;
                return true;
              }
            });
          });
        });
    },
    clickAllTwo() {
      this.twoIndex=""
      this.threeIndex = "";
      this.changeData();
    },
    clickAll() {
      this.threeIndex = "";
      this.changeData();
    },
    changeSortType(type) {
      this.sortType = type;
      switch (type) {
        case "price":
          if (this.priceSort == "asc") {
            this.priceSort = "desc";
          } else if (this.priceSort == "desc") {
            this.priceSort = "asc";
          }
          break;
        case "sales_sum":
          if (this.saleSort == "asc") {
            this.saleSort = "desc";
          } else if (this.saleSort == "desc") {
            this.saleSort = "asc";
          }
          break;
        default:
      }
      this.getGoods();
    },
    changePage(current) {
      this.page = current;
      this.getGoods();
    },
    async getGoods() {
      const {
        priceSort,
        sortType,
        saleSort,
      } = this;
      let category_id = this.cateId;
      let sort = "";
      switch (sortType) {
        case "price":
          sort = priceSort;
          break;
        case "sales_sum":
          sort = saleSort;
          break;
      }
      const {
        data: { list, count },
      } = await this.$get("pc/goodsList", {
        params: {
          page_size: 20,
          page_no: this.page,
          sort_type: sortType,
          sort,
          category_id,
        },
      });
      this.goodsList = list;
      if (!list.length) {
        this.isHasGoods = false;
      } else {
        this.isHasGoods = true;
      }
      this.count = count;
    },
  },
  watch: {
    categoryList: {
      immediate: true,
      handler(value) {
        const { id } = this.$route.query;
        this.changeData(Number(id));
      },
    },
  },
};
